{
  "query": "query ($search: String, $page: Int, $perPage: Int) { Page(page: $page, perPage: $perPage) { pageInfo { total currentPage lastPage hasNextPage perPage } media(search: $search, type: ANIME, isAdult: false, sort: [SEARCH_MATCH]) { id title { romaji english native } format status episodes genres averageScore popularity } } }",
  "variables": {
    "search": "{{anime_search}}",
    "page": "{{common_page}}",
    "perPage": "{{common_page_size}}"
  }
}

{
  "query": "query ($id: Int) { Media(id: $id, type: ANIME) { id title { romaji english native } description format status episodes duration genres averageScore popularity season seasonYear nextAiringEpisode { airingAt episode } } }",
  "variables": {
    "id": "{{anilist_media_id}}"
  }
}

{
  "query": "query ($search: String, $page: Int, $perPage: Int) { Page(page: $page, perPage: $perPage) { pageInfo { total currentPage lastPage hasNextPage perPage } media(search: $search, type: ANIME, isAdult: false, sort: [SEARCH_MATCH]) { id title { romaji english native } format status episodes genres averageScore popularity } } }",
