    "id": "{{anilist_media_id}}"
  }
}

{
  "query": "query($season: MediaSeason, $seasonYear: Int, $nextSeason: MediaSeason, $nextYear: Int, $perPage: Int) { trending: Page(page: 1, perPage: $perPage) { media(sort: TRENDING_DESC, type: ANIME, isAdult: false) { id title { romaji english native } } } season: Page(page: 1, perPage: $perPage) { media(season: $season, seasonYear: $seasonYear, sort: POPULARITY_DESC, type: ANIME, isAdult: false) { id title { romaji english native } } } nextSeason: Page(page: 1, perPage: $perPage) { media(season: $nextSeason, seasonYear: $nextYear, sort: POPULARITY_DESC, type: ANIME, isAdult: false) { id title { romaji english native } } } }",
  "variables": {
    "season": "SPRING",
    "seasonYear": 2026,
    "nextSeason": "SUMMER",
    "nextYear": 2026,
    "perPage": 10
  }
}

{
  "query": "query { Viewer { id name siteUrl avatar { large medium } mediaListOptions { scoreFormat } statistics { anime { count meanScore minutesWatched episodesWatched } manga { count meanScore chaptersRead volumesRead } } } }",
  "variables": {}
}

{
  "query": "query ($userId: Int!, $type: MediaType!, $status: MediaListStatus) { MediaListCollection(userId: $userId, type: $type, status: $status) { lists { name status entries { id status score progress progressVolumes repeat notes updatedAt media { id title { romaji english native } coverImage { large medium } format status episodes chapters volumes averageScore popularity } } } } }",
  "variables": {
    "userId": "{{anilist_user_id}}",
    "type": "ANIME",
    "status": "CURRENT"
  }
}

{
  "query": "mutation ($mediaId: Int!, $status: MediaListStatus, $score: Float, $progress: Int) { SaveMediaListEntry(mediaId: $mediaId, status: $status, score: $score, progress: $progress) { id mediaId status score progress updatedAt } }",
  "variables": {
    "mediaId": "{{anilist_media_id}}",
    "status": "CURRENT",
    "score": 8,
    "progress": 1
  }
}

